mapper.select:
select
  (
    select count(1)
    from payment_channel_capability cc
    where cc.tenant_id = #{tenantId}
      and cc.method_code = #{methodCode}
  )
  + (
    select count(1)
    from payment_channel_contract_capability ccc
    where ccc.tenant_id = #{tenantId}
      and ccc.del_flag = 0
      and ccc.method_code = #{methodCode}
  )
  + (
    select count(1)
    from payment_method_route_rule rr
    where rr.tenant_id = #{tenantId}
      and rr.method_code = #{methodCode}
  )
  + (
    select count(1)
    from payment_cashier_config c
    where c.tenant_id = #{tenantId}
      and c.del_flag = 0
      and (
        find_in_set(#{methodCode}, c.method_codes)
        or c.default_method_code = #{methodCode}
        or find_in_set(#{methodCode}, c.method_display_order)
      )
  )
  + (
    select count(1)
    from payment_order po
    where po.tenant_id = #{tenantId}
      and po.method_id = #{methodId}
  )
  + (
    select count(1)
    from payment_virtual_channel_payment sp
    where sp.tenant_id = #{tenantId}
      and (
        sp.payment_method_id = #{methodId}
        or sp.payment_method_code = #{methodCode}
      )
  )
